#!/bin/bash
# User Management Script

show_menu() {
  echo "=== User Management ==="
  echo "1. List all users"
  echo "2. Check user details"
  echo "3. Lock user account"
  echo "4. Exit"
  echo ""
}

get_user_info() {
  local username=$1
  if id "$username" &>/dev/null; then
    echo "Username: $username"
    echo "UID: $(id -u $username)"
    echo "Home: $(eval echo ~$username)"
    echo "Shell: $(grep ^$username /etc/passwd | cut -d: -f7)"
  else
    echo "User not found: $username"
  fi
}

while true; do
  show_menu
  read -p "Select option: " choice

  case $choice in
    1) echo "Current Users:"; getent passwd | cut -d: -f1 ;;
    2) read -p "Enter username: " user; get_user_info "$user" ;;
    3) echo "Lock feature requires root access" ;;
    4) echo "Exiting..."; exit 0 ;;
    *) echo "Invalid option" ;;
  esac
  echo ""
done
